            // ========== 02-SAUNA ==========
            ['key' => 'angebote2.sauna.title', 'section' => 'pages.angebote2.sauna',
             'fr' => 'Sauna', 'de' => 'Sauna', 'en' => 'Sauna'],
            ['key' => 'angebote2.sauna.desc1', 'section' => 'pages.angebote2.sauna',
             'fr' => 'Si vous aimez la chaleur, vous êtes exactement au bon endroit dans le sauna du Centre de Loisirs Mundial.',
             'de' => 'Wenn Sie Wärme lieben, sind Sie in der Sauna des Freizeitzentrums Mundial genau am richtigen Ort.',
             'en' => 'If you love heat, you are in exactly the right place in the sauna of the Mundial leisure center.',
             'id' => 'Jika Anda menyukai panas, Anda berada di tempat yang tepat di sauna pusat hiburan Mundial.'],
            ['key' => 'angebote2.sauna.desc2', 'section' => 'pages.angebote2.sauna',
             'fr' => "Notre espace sauna s'étend sur environ 1'500 m². Vivez la fascination de la chaleur dans l'un de nos cinq saunas aux températures différentes.",
             'de' => "Unser Saunabereich erstreckt sich über etwa 1'500 m². Erleben Sie die Faszination der Wärme in einer unserer fünf Saunen mit unterschiedlichen Temperaturen.",
             'en' => "Our sauna space extends over about 1'500 m². Experience the fascination of heat in one of our five saunas with different temperatures.",
             'id' => "Area sauna kami mencakup sekitar 1.500 m². Rasakan pesona kehangatan di salah satu dari lima sauna kami dengan suhu berbeda."],
            ['key' => 'angebote2.sauna.desc3', 'section' => 'pages.angebote2.sauna',
             'fr' => 'Que ce soit en hiver ou en été, le sauna est une forme particulière d\'application chaud-froid qui favorise la santé et sert à se détendre. Entre autres, le sauna stimule le métabolisme, stabilise le système cardiovasculaire et aide à entraîner le système vasculaire.',
             'de' => 'Ob im Winter oder im Sommer ist die Sauna eine besondere Form der Warm-Kalt-Anwendung, die die Gesundheit fördert und der Entspannung dient. Unter anderem regt die Sauna den Stoffwechsel an, stabilisiert das Herz-Kreislauf-System und hilft bei der Schulung des Gefäßsystems.',
             'en' => 'Whether in winter or summer, the sauna is a special form of hot-cold application that promotes health and serves relaxation. Among other things, the sauna stimulates metabolism, stabilizes the cardiovascular system and helps train the vascular system.',
             'id' => 'Baik di musim dingin maupun musim panas, sauna adalah bentuk khusus aplikasi panas-dingin yang meningkatkan kesehatan dan melayani relaksasi. Antara lain, sauna merangsang metabolisme, menstabilkan sistem kardiovaskular dan membantu melatih sistem pembuluh darah.'],
            ['key' => 'angebote2.sauna.desc4', 'section' => 'pages.angebote2.sauna',
