            $key = $trans['key'];
            $section = $trans['section'];
            foreach (['fr', 'de', 'en', 'id'] as $lang) {
                if (!isset($trans[$lang])) continue;
                Translation::updateOrCreate(
                    ['key' => $key, 'language' => $lang],
                    ['section' => $section, 'value' => $trans[$lang], 'type' => 'text']
                );
            }
